import{_ as o,o as r,c as a,a0 as t}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Run a KvK Prep Session","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/kvk-prep.md","filePath":"how-to/kvk-prep.md"}'),i={name:"how-to/kvk-prep.md"};function l(s,e,n,p,h,c){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="run-a-kvk-prep-session" tabindex="-1">Run a KvK Prep Session <a class="header-anchor" href="#run-a-kvk-prep-session" aria-label="Permalink to &quot;Run a KvK Prep Session&quot;">​</a></h1><p>KvK Prep is the dedicated before-and-after power workflow for <strong>Kingdom of Power</strong>. It is separate from normal event-result imports.</p><blockquote><p>Screenshot placeholder: kvk-prep.png Screenshot placeholder: kvk-export.png</p></blockquote><h2 id="what-this-page-is-for" tabindex="-1">What this page is for <a class="header-anchor" href="#what-this-page-is-for" aria-label="Permalink to &quot;What this page is for&quot;">​</a></h2><p>Use KvK Prep to:</p><ul><li>pick a Kingdom of Power window</li><li>capture <strong>before</strong> power</li><li>capture <strong>after</strong> power</li><li>review growth</li><li>export a PDF report</li></ul><h2 id="two-ways-to-capture-power" tabindex="-1">Two ways to capture power <a class="header-anchor" href="#two-ways-to-capture-power" aria-label="Permalink to &quot;Two ways to capture power&quot;">​</a></h2><p>You can save data in two ways:</p><ul><li><strong>Manual Snapshot Entry</strong> for typed power values</li><li><strong>Screenshot Import</strong> for alliance member list OCR</li></ul><p>The screenshot path is careful by design: process the image first, review the rows, then apply them into the selected before or after snapshot.</p><h2 id="the-basic-workflow" tabindex="-1">The basic workflow <a class="header-anchor" href="#the-basic-workflow" aria-label="Permalink to &quot;The basic workflow&quot;">​</a></h2><ol><li>Select the KvK window.</li><li>Choose <strong>Before</strong> or <strong>After</strong>.</li><li>Enter power manually or process an alliance member screenshot.</li><li>Review the preview rows.</li><li>Approve and apply them.</li><li>Repeat until both before and after coverage are complete.</li></ol><h2 id="what-the-page-helps-you-monitor" tabindex="-1">What the page helps you monitor <a class="header-anchor" href="#what-the-page-helps-you-monitor" aria-label="Permalink to &quot;What the page helps you monitor&quot;">​</a></h2><p>KvK Prep shows:</p><ul><li>tracked players</li><li>how many before rows are saved</li><li>how many after rows are saved</li><li>reminder windows</li><li>growth report sorted by percentage gain</li><li>alliance summary, when you are not locked to one alliance</li></ul><h2 id="screenshot-processing-notes" tabindex="-1">Screenshot processing notes <a class="header-anchor" href="#screenshot-processing-notes" aria-label="Permalink to &quot;Screenshot processing notes&quot;">​</a></h2><p>For KvK uploads, the page supports:</p><ul><li>Free Local Processing</li><li>Gemini</li><li>paste from clipboard</li></ul><p>After processing, you can:</p><ul><li>edit rows</li><li>rematch rows</li><li>accept rows</li><li>ignore rows</li></ul><p>Only then should you use <strong>Approve &amp; apply</strong>.</p><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><p>The growth report includes a <strong>Download PDF Report</strong> action for sharing the final result.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../events/kingdom-of-power.html">Kingdom of Power</a></li><li><a href="./../imports/review-rows.html">Review Import Rows</a></li><li><a href="./../imports/apply-import.html">Accept Rows (Apply an Import)</a></li></ul>',25)])])}const u=o(i,[["render",l]]);export{d as __pageData,u as default};
